+	if err := validateThreshold("thresholds.dashboard", cfg.Thresholds.Dashboard); err != nil {
+		return err
+	}
+	if err := validateThreshold("thresholds.interactive", cfg.Thresholds.Interactive); err != nil {
+		return err
+	}
