+	}
+
+	disabled := make(map[string]struct{}, len(cfg.Tools.Disabled))
+	for _, tool := range cfg.Tools.Disabled {
+		disabled[tool] = struct{}{}
+	}
+	for _, tool := range cfg.Tools.Enabled {
+		if _, ok := disabled[tool]; ok {
